async (page) => {
  // Extract story title
  const title = await page.locator('td.title a').first().textContent();
  // Extract points
  const pointsText = await page.locator('span.score').first().textContent();
  const points = pointsText ? parseInt(pointsText.match(/\d+/)[0]) : 0;
  // Extract total comments - look for the comments header or count
  const commentsHeader = await page.locator('td.subtext a').last().textContent();
  const totalComments = commentsHeader ? parseInt(commentsHeader.match(/\d+/)[0]) : 0;

  // Find top-level comments
  const topLevelComments = await page.locator('div.comment').filter({ has: page.locator('[style*="margin-left:0px"]') }).all();

  let maxReplies = 0;
  let topAuthor = '';

  for (const comment of topLevelComments) {
    // Count direct replies: comments with margin-left:40px that follow this comment
    const commentBox = comment.locator('..').locator('..'); // get the parent
    const nextTopLevel = commentBox.locator('xpath=following-sibling::div[contains(@class, "comment")][1]');
    let repliesCount = 0;

    if (await nextTopLevel.count() > 0) {
      const replies = commentBox.locator('xpath=following-sibling::div[contains(@class, "comment")][preceding-sibling::div[contains(@class, "comment")][1] = .]');
      repliesCount = await replies.count();
    } else {
      // Count all following comments until end
      const allFollowing = commentBox.locator('xpath=following-sibling::div[contains(@class, "comment")]');
      repliesCount = await allFollowing.count();
    }

    if (repliesCount > maxReplies) {
      maxReplies = repliesCount;
      const authorLink = await comment.locator('span.comhead a[href^="user?id="]').first().textContent();
      topAuthor = authorLink;
    }
  }

  return {
    title: title.trim(),
    points: points,
    totalComments: totalComments,
    topAuthor: topAuthor.trim()
  };
}

