async (page) => {
  const title = await page.locator('td.title a').textContent();
  const pointsText = await page.locator('span.score').textContent();
  const points = parseInt(pointsText.match(/\d+/)[0]);
  const commentsText = await page.locator('td.subtext a').last().textContent();
  const totalComments = parseInt(commentsText.match(/\d+/)[0]);

  const topLevelComments = await page.$$('div.comment[style*="margin-left:0px"]');

  let maxReplies = 0;
  let topAuthor = '';

  for (const comment of topLevelComments) {
    const commentElement = comment;
    const nextTopLevel = await page.evaluate((el) => {
      let current = el;
      while (current) {
        current = current.nextElementSibling;
        if (current && current.classList.contains('comment') && current.style.marginLeft === '0px') {
          return current;
        }
      }
      return null;
    }, commentElement);

    let replies = 0;
    if (nextTopLevel) {
      replies = await page.evaluate((start, end) => {
        let count = 0;
        let current = start.nextElementSibling;
        while (current && current !== end) {
          if (current.classList.contains('comment') && current.style.marginLeft === '40px') {
            count++;
          }
          current = current.nextElementSibling;
        }
        return count;
      }, commentElement, nextTopLevel);
    } else {
      replies = await page.evaluate((start) => {
        let count = 0;
        let current = start.nextElementSibling;
        while (current) {
          if (current.classList.contains('comment') && current.style.marginLeft === '40px') {
            count++;
          }
          current = current.nextElementSibling;
        }
        return count;
      }, commentElement);
    }

    if (replies > maxReplies) {
      maxReplies = replies;
      const authorElement = await comment.$('span.comhead a[href^="user?id="]');
      if (authorElement) {
        topAuthor = await authorElement.textContent();
      }
    }
  }

  return { title: title.trim(), points, totalComments, topAuthor: topAuthor.trim() };
}

